enum IntegrityRisk: String {
    case jailbroken = "Device is jailbroken"
    case debuggerDetected = "Debugger detected"
    case suspiciousAppsInstalled = "Suspicious apps installed"
    case simulator = "Running on simulator"
    case functionHooking = "Function hooking detected"
}

struct DeviceIntegrityStatus {
    let risks: [IntegrityRisk]
    
    var isCompromised: Bool {
        return !risks.isEmpty
    }
    
    var isCriticallyCompromised: Bool {
        return risks.contains(.jailbroken) || risks.contains(.functionHooking)
    }
    
    var riskLevel: RiskLevel {
        if risks.contains(.jailbroken) || risks.contains(.functionHooking) {
            return .critical
        } else if !risks.isEmpty {
            return .medium
        } else {
            return .low
        }
    }
}

enum RiskLevel {
    case low
    case medium
    case critical
}

