class SecureStorageManager {
    static let shared = SecureStorageManager()
    
    private let serviceName = "com.bankingapp.secure"
    private let encryptionKey: SymmetricKey
    
    private init() {
        if let existingKey = Self.retrieveEncryptionKey() {
            self.encryptionKey = existingKey
        } else {
            self.encryptionKey = SymmetricKey(size: .bits256)
            Self.storeEncryptionKey(self.encryptionKey)
        }
    }
    
    func saveSecureData(_ data: Data, forKey key: String) throws {
