enum SecurityError: Error {
    case deviceCompromised
    case integrityCheckFailed
    case encryptionFailed
    case decryptionFailed
    case keychainError(OSStatus)
    case invalidSignature
    case transactionValidationFailed
    case insufficientFunds
    case unauthorizedAccess
}

// MARK: - Transaction Processor
class TransactionProcessor {
    static let shared = TransactionProcessor()
    private let secureStorage = SecureStorageManager.shared
    private let integrityChecker = DeviceIntegrityChecker.shared
    
    private init() {}
    
    func processTransaction(_ transaction: Transaction) throws -> Transaction {
        let integrityStatus = integrityChecker.performIntegrityCheck()
        
        if integrityStatus.isCriticallyCompromised {
            logSecurityEvent("Transaction blocked: Device critically compromised", risks: integrityStatus.risks)
            throw SecurityError.deviceCompromised
        }
        
        if integrityStatus.isCompromised {
            logSecurityEvent("Transaction processed with elevated monitoring: Device integrity compromised", risks: integrityStatus.risks)
            try performEnhancedValidation(transaction)
        }
        
        try validateTransaction(transaction)
        
        try verifyTransactionSignature(transaction)
        
        var updatedTransaction = transaction
        updatedTransaction = Transaction(
            id: transaction.id,
            amount: transaction.amount,
            fromAccount: transaction.fromAccount,
            toAccount: transaction.toAccount,
            timestamp: transaction.timestamp,
            description: transaction.description,
            status: .completed,
            signature: transaction.signature
        )
        
        try saveTransaction(updatedTransaction)
        
        try updateAccountBalances(transaction)
        
        return updatedTransaction
    }
    
    private func performEnhancedValidation(_ transaction: Transaction) throws {
        if transaction.amount > 1000 {
            throw SecurityError.transactionValidationFailed
        }
        
        let recentTransactions = try getRecentTransactions(forAccount: transaction.fromAccount, hours: 1)
        let totalAmount = recentTransactions.reduce(Decimal(0)) { $0 + $1.amount }
        
        if totalAmount + transaction.amount > 5000 {
            throw SecurityError.transactionValidationFailed
        }
    }
    
    private func validateTransaction(_ transaction: Transaction) throws {
        guard transaction.amount > 0 else {
            throw SecurityError.transactionValidationFailed
        }
        
        let fromAccount = try getAccount(transaction.fromAccount)
        guard fromAccount.balance >= transaction.amount else {
            throw SecurityError.insufficientFunds
        }
    }
    
    private func verifyTransactionSignature(_ transaction: Transaction) throws {
        let dataToSign = "\(transaction.id)\(transaction.amount)\(transaction.fromAccount)\(transaction.toAccount)\(transaction.timestamp.timeIntervalSince1970)"
        
        guard let data = dataToSign.data(using: .utf8) else {
            throw SecurityError.invalidSignature
        }
        
        let hash = SHA256.hash(data: data)
        let computedSignature = hash.compactMap { String(format: "%02x", $0) }.joined()
        
        guard computedSignature == transaction.signature else {
            throw SecurityError.invalidSignature
        }
    }
    
    private func saveTransaction(_ transaction: Transaction) throws {
        let encoder = JSONEncoder()
        let data = try encoder.encode(transaction)
        try secureStorage.saveSecureData(data, forKey: "transaction_\(transaction.id)")
    }
    
    private func updateAccountBalances(_ transaction: Transaction) throws {
        var fromAccount = try getAccount(transaction.fromAccount)
        var toAccount = try getAccount(transaction.toAccount)
        
        fromAccount.balance -= transaction.amount
        toAccount.balance += transaction.amount
        
        try saveAccount(fromAccount)
        try saveAccount(toAccount)
    }
    
    func getAccount(_ accountNumber: String) throws -> Account {
        let data = try secureStorage.retrieveSecureData(forKey: "account_\(accountNumber)")
        let decoder = JSONDecoder()
        return try decoder.decode(Account.self, from: data)
    }
    
    func saveAccount(_ account: Account) throws {
        let encoder = JSONEncoder()
        let data = try encoder.encode(account)
        try secureStorage.saveSecureData(data, forKey: "account_\(account.accountNumber)")
    }
    
    func getAccountBalance(_ accountNumber: String) throws -> Decimal {
        let integrityStatus = integrityChecker.performIntegrityCheck()
        
        if integrityStatus.isCriticallyCompromised {
            logSecurityEvent("Balance access blocked: Device critically compromised", risks: integrityStatus.risks)
            throw SecurityError.deviceCompromised
        }
        
        if integrityStatus.isCompromised {
            logSecurityEvent("Balance accessed with elevated monitoring: Device integrity compromised", risks: integrityStatus.risks)
        }
        
        let account = try getAccount(accountNumber)
        return account.balance
    }
    
    private func getRecentTransactions(forAccount accountNumber: String, hours: Int) throws -> [Transaction] {
        return []
    }
    
    private func logSecurityEvent(_ message: String, risks: [IntegrityRisk]) {
        let riskDescriptions = risks.map { $0.rawValue }.joined(separator: ", ")
        print("🔒 SECURITY EVENT: \(message) - Risks: \(riskDescriptions)")
    }
}

