        label.font = UIFont.systemFont(ofSize: 16, weight: .regular)
        label.textAlignment = .center
        label.textColor = .gray
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let securityStatusLabel: UILabel = {
        let label = UILabel()
        label.font = UIFont.systemFont(ofSize: 14, weight: .medium)
        label.textAlignment = .center
        label.numberOfLines = 0
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let transferButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Transfer Funds", for: .normal)
        button.titleLabel?.font = UIFont.systemFont(ofSize: 18, weight: .semibold)
        button.backgroundColor = .systemBlue
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 10
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private var currentAccount: Account?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        performSecurityCheck()
        loadAccountData()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Banking"
        
        view.addSubview(securityStatusLabel)
        view.addSubview(accountNumberLabel)
        view.addSubview(balanceLabel)
        view.addSubview(transferButton)
        
        NSLayoutConstraint.activate([
            securityStatusLabel.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            securityStatusLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            securityStatusLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            accountNumberLabel.topAnchor.constraint(equalTo: securityStatusLabel.bottomAnchor, constant: 40),
            accountNumberLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            balanceLabel.topAnchor.constraint(equalTo: accountNumberLabel.bottomAnchor, constant: 10),
            balanceLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            transferButton.topAnchor.constraint(equalTo: balanceLabel.bottomAnchor, constant: 40),
            transferButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            transferButton.widthAnchor.constraint(equalToConstant: 200),
            transferButton.heightAnchor.constraint(equalToConstant: 50)
        ])
        
        transferButton.addTarget(self, action: #selector(transferButtonTapped), for: .touchUpInside)
    }
    
    private func performSecurityCheck() {
        let integrityStatus = integrityChecker.performIntegrityCheck()
        
        if integrityStatus.isCriticallyCompromised {
            securityStatusLabel.text = "⚠️ CRITICAL SECURITY RISK DETECTED\nSome features are restricted"
            securityStatusLabel.textColor = .systemRed
            transferButton.isEnabled = false
            transferButton.backgroundColor = .systemGray
            
            showSecurityAlert(status: integrityStatus)
        } else if integrityStatus.isCompromised {
            securityStatusLabel.text = "⚠️ Security Warning: Device integrity compromised\nTransactions are limited"
            securityStatusLabel.textColor = .systemOrange
        } else {
            securityStatusLabel.text = "✓ Device Secure"
            securityStatusLabel.textColor = .systemGreen
        }
    }
    
    private func showSecurityAlert(status: DeviceIntegrityStatus) {
        let risks = status.risks.map { $0.rawValue }.joined(separator: "\n")
        let alert = UIAlertController(
            title: "Security Risk Detected",
            message: "Your device has security risks that prevent certain banking operations:\n\n\(risks)\n\nPlease use a secure device for banking transactions.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func loadAccountData() {
        do {
            let accountNumber = "1234567890"
            let balance = try transactionProcessor.getAccountBalance(accountNumber)
            
            accountNumberLabel.text = "Account: ****\(accountNumber.suffix(4))"
            balanceLabel.text = "$\(balance)"
            
            currentAccount = try transactionProcessor.getAccount(accountNumber)
        } catch SecurityError.deviceCompromised {
            showError("Cannot access account: Device security compromised")
        } catch {
            showError("Failed to load account data: \(error.localizedDescription)")
        }
    }
    
    @objc private func transferButtonTapped() {
        let integrityStatus = integrityChecker.performIntegrityCheck()
        
        if integrityStatus.isCriticallyCompromised {
            showError("Transfers are disabled due to device security risks")
            return
        }
        
        performTransfer()
    }
    
    private func performTransfer() {
        guard let account = currentAccount else { return }
        
        let transaction = Transaction(
            id: UUID().uuidString,
            amount: Decimal(100),
            fromAccount: account.accountNumber,
            toAccount: "9876543210",
            timestamp: Date(),
            description: "Transfer",
            status: .pending,
            signature: generateSignature(for: UUID().uuidString, amount: Decimal(100), timestamp: Date())
        )
        
        do {
            let completedTransaction = try transactionProcessor.processTransaction(transaction)
            showSuccess("Transfer completed successfully")
            loadAccountData()
        } catch SecurityError.deviceCompromised {
            showError("Transfer blocked: Device security compromised")
        } catch SecurityError.transactionValidationFailed {
            showError("Transfer blocked: Transaction limits exceeded on compromised device")
        } catch {
            showError("Transfer failed: \(error.localizedDescription)")
        }
    }
    
    private func generateSignature(for id: String, amount: Decimal, timestamp: Date) -> String {
        let dataToSign = "\(id)\(amount)1234567890\("9876543210")\(timestamp.timeIntervalSince1970)"
        guard let data = dataToSign.data(using: .utf8) else { return "" }
        let hash = SHA256.hash(data: data)
        return hash.compactMap { String(format: "%02x", $0) }.joined()
    }
    
    private func showError(_ message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func showSuccess(_ message: String) {
        let alert = UIAlertController(title: "Success", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

